#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
const int INF=0x3f3f3f3f;bool a[110][110];int n,m,L[210],K,dp[210][110];
int main()
{
//	FIN("data.in");FOUT("mine.out");
	int T=read();Begin:
	
	memset(a,0,sizeof(a));n=read();m=read();
	while(m--){int x=read(),y=read();a[x][y]=a[y][x]=true;}rep(1,n,i)a[i][i]=true;
	K=read();rep(1,K,i)L[i]=read();rep(1,n,i)a[i][0]=a[0][i]=true;
	memset(dp,0x3f,sizeof(dp));rep(1,n,i)if(i==L[1])dp[1][i]=0;else dp[1][i]=1;
	rep(2,K,i)
	{
		rep(1,n,j)if(a[L[i]][j])dp[i][L[i]]=min(dp[i][L[i]],dp[i-1][j]);
		rep(1,n,j)if(j!=L[i]){rep(1,n,k)if(a[j][k])dp[i][j]=min(dp[i][j],dp[i-1][k]+1);}
	}
//	rep(1,K,i){printf("%d :: ",i);rep(0,n,j)printf("%d ",dp[i][j]==INF?-1:dp[i][j]);puts("");}
	int ans=K;rep(1,n,i)ans=min(ans,dp[K][i]);printf("%d\n",ans);
	
	if(--T)goto Begin;return 0;
}
